-- 1. Add COMPLETE INTERIOR COMPOSITION to existing 12 bedroom scenes
UPDATE product_image_scenes
SET prompt_template = regexp_replace(
  prompt_template,
  'Create a premium lifestyle interior image placing',
  E'CRITICAL — COMPLETE INTERIOR COMPOSITION: This is a full room interior photograph, NOT a product-only shot. The product from the reference image must be placed naturally inside a fully furnished, realistic bedroom. The room must contain a balanced mix of complementary furniture and decor appropriate to the scene:\n• If the product is a BED or HEADBOARD: add matching nightstands on both sides with lamps, a textured area rug beside/under the bed, a throw or blanket layered on the bed, wall art or a mirror above, and optionally a bench or chair at the foot.\n• If the product is a NIGHTSTAND or SIDE TABLE: show it beside a properly made bed with bedding, a lamp on top, and the rest of the bedroom visible (rug, art, opposite nightstand).\n• If the product is a DRESSER or CHEST: place it against the wall in a bedroom that also contains a fully styled bed with nightstands, rug, and lighting in the background or mid-ground.\n• If the product is a WARDROBE or CLOSET: position it along a wall with a full bedroom arrangement (bed, nightstands, rug, seating) visible in the composition.\n• If the product is a CHAIR, BENCH, or OTTOMAN: show it at the foot of the bed or in a reading corner, with the full bedroom (bed, nightstands, rug, lighting) as context.\n• If the product is a RUG: lay it beside or under the bed with the full bedroom suite (bed, nightstands, lamps, art) visible above.\n• If the product is a LAMP or LIGHTING FIXTURE: show it on a nightstand or as a floor lamp beside seating, with the complete bedroom visible.\nThe scene must look like a real inhabited, decorated bedroom — never an isolated product in an empty room. Every complementary piece must match the room''s aesthetic and color palette.\n\nCreate a premium lifestyle interior image placing'
)
WHERE scene_id IN (
  'furniture-lifestyle-linen-cloud-suite',
  'furniture-lifestyle-parisian-pied-a-terre',
  'furniture-lifestyle-coastal-dawn-retreat',
  'furniture-lifestyle-warm-walnut-sanctuary',
  'furniture-lifestyle-scandi-hygge-nest',
  'furniture-lifestyle-terracotta-linen-villa',
  'furniture-lifestyle-japandi-sleep-temple',
  'furniture-lifestyle-hamptons-morning-suite',
  'furniture-lifestyle-milanese-atelier-bedroom',
  'furniture-lifestyle-desert-stone-retreat',
  'furniture-lifestyle-skyline-penthouse-bedroom',
  'furniture-lifestyle-garden-conservatory-bedroom'
);

-- 2. Fix "visual hero" / "visually dominant" phrasing
UPDATE product_image_scenes
SET prompt_template = regexp_replace(
  prompt_template,
  'The furniture must remain [^.]+\.',
  'The product must be the primary focal point within a fully furnished, balanced interior — correctly scaled and grounded in the space.'
)
WHERE scene_id IN (
  'furniture-lifestyle-linen-cloud-suite',
  'furniture-lifestyle-parisian-pied-a-terre',
  'furniture-lifestyle-coastal-dawn-retreat',
  'furniture-lifestyle-warm-walnut-sanctuary',
  'furniture-lifestyle-scandi-hygge-nest',
  'furniture-lifestyle-terracotta-linen-villa',
  'furniture-lifestyle-japandi-sleep-temple',
  'furniture-lifestyle-hamptons-morning-suite',
  'furniture-lifestyle-milanese-atelier-bedroom',
  'furniture-lifestyle-desert-stone-retreat',
  'furniture-lifestyle-skyline-penthouse-bedroom',
  'furniture-lifestyle-garden-conservatory-bedroom'
);

