INSERT INTO product_image_scenes (scene_id, title, description, scene_type, category_collection, sub_category, sort_order, is_active, prompt_template, trigger_blocks, filter_tags)
VALUES
('furniture-lifestyle-quiet-luxury-moody-suite', 'Quiet Luxury Moody Suite', 'Dark chocolate and warm amber bedroom with fluted wood paneling', 'lifestyle', 'furniture', 'Bedroom', 154, true,
E'Use [PRODUCT IMAGE] as the exact source of truth for {{productName}}, preserving exact structure, scale, finish, proportions, and all product details.\n\nCRITICAL — PROPORTIONAL SCALE RULE: Calculate the product''s real-world size as a fraction of the room width. A 180cm bed in a 5m-wide room occupies roughly 36% of the wall. A 60cm nightstand spans 12% of a 5m wall. Use these proportions strictly. HUMAN SCALE ANCHOR: Imagine a 175cm adult lying on the bed or standing beside the product — the product must look dimensionally correct. ARCHITECTURAL CALIBRATION: The standard interior door (210cm × 90cm) is your ruler. NEVER let the product fill more than 45% of the visible wall unless its real dimensions require it.\n\nCRITICAL — COMPLETE INTERIOR COMPOSITION: This is a full room interior photograph, NOT a product-only shot. The product from the reference image must be placed naturally inside a fully furnished, realistic bedroom. The room must contain a balanced mix of complementary furniture and decor:\n• If the product is a BED or HEADBOARD: add matching nightstands on both sides with lamps, a textured area rug, a throw, wall art or mirror, and optionally a bench or chair at the foot.\n• If the product is a NIGHTSTAND, DRESSER, CHAIR, BENCH, RUG, or LAMP: integrate it into a complete bedroom with all expected furnishings visible.\nThe scene must look like a real inhabited, decorated bedroom — never an isolated product in an empty room.\n\nCreate a premium lifestyle interior image placing {{productName}} in a moody quiet-luxury bedroom (approximately 5m × 4.5m, 2.8m ceiling) with dark-stained wide-plank walnut flooring. Feature wall behind the bed in vertical fluted dark oak paneling (warm chocolate brown). Remaining walls in deep warm taupe limewash plaster. Two tall windows (2m) with heavy dark linen curtains in charcoal, partially drawn.\n\nSTYLED INTERIOR DETAILS: Rich chocolate velvet bedding layered with a cashmere throw in warm amber. Two sculptural nightstands in dark bronze with integrated reading lamps emitting warm pools of light. A large abstract artwork in muted earth tones (burnt sienna, raw umber) above the headboard. A deep boucle armchair in warm taupe at the foot of the bed beside a slim brass floor lamp. A thick hand-knotted wool rug in warm charcoal beside the bed. A dark ceramic vase with dried eucalyptus on the dresser.\n\nThe product must be the primary focal point within a fully furnished, balanced interior — correctly scaled and grounded in the space. Color palette: dark chocolate, warm amber, deep taupe, bronze, charcoal. Rich, enveloping, whisper-quiet luxury.\n\nLighting: warm amber accent lighting from nightstand lamps and floor lamp. Low, intimate, golden. Deep shadows in corners creating depth.\n\nShot with 35mm lens, eye-level, centered composition. Quiet luxury editorial — Cereal Magazine aesthetic. Photorealistic. No text.',
'{}', '{}'),

